  const league = getLeagueConfigById(leagueId ?? "");
  return !!league?.supportsOdds;
}

export function supportsLiveDetailsForLeague(leagueId?: string): boolean {
  const league = getLeagueConfigById(leagueId ?? "");
  return !!league?.supportsLiveDetails;
}

